<style>
  .gp-stat-row {
    display: grid;
    grid-template-columns: 1fr 1fr 1fr;
    gap: 10px;
    width: 100%;
    box-sizing: border-box;
    margin-bottom: 16px;
  }
  .gp-stat-box {
    background: #fff;
    border: 1.5px solid #EF3340;
    border-radius: 12px;
    padding: 14px 10px;
    text-align: center;
    box-sizing: border-box;
  }
  .gp-stat-main {
    display: flex;
    align-items: baseline;
    justify-content: center;
    gap: 2px;
  }
  .gp-stat-num {
    font-size: 32px;
    font-weight: 900;
    color: #EF3340;
    line-height: 1;
  }
  .gp-stat-unit {
    font-size: 13px;
    font-weight: 700;
    color: #EF3340;
    line-height: 1;
    text-transform: uppercase;
  }
  .gp-stat-label {
    font-size: 12px;
    color: #140A0A;
    margin-top: 6px;
    font-weight: 700;
  }

  .gp-feat-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 10px;
    margin-bottom: 16px;
  }
  .gp-feat-card {
    background: #fff;
    border: 1.5px solid #e0dcdc;
    border-radius: 12px;
    padding: 14px 12px;
    display: flex;
    align-items: flex-start;
    gap: 12px;
    box-sizing: border-box;
  }
  .gp-feat-icon {
    width: 38px;
    height: 38px;
    border-radius: 10px;
    background: #EF3340;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
  }
  .gp-feat-icon svg {
    width: 18px;
    height: 18px;
  }
  .gp-feat-title {
    font-size: 13px;
    font-weight: 700;
    color: #140A0A;
    margin-bottom: 3px;
    line-height: 1.2;
  }
  .gp-feat-body {
    font-size: 12px;
    color: #888;
    line-height: 1.5;
