  .gp-use-pill {
    background: #fff;
    border: 1.5px solid #e0dcdc;
    border-radius: 30px;
    padding: 10px 14px;
    font-size: 13px;
    font-weight: 600;
    color: #333;
    display: flex;
    align-items: center;
    gap: 8px;
  }
  .gp-use-dot {
    width: 7px;
    height: 7px;
    border-radius: 50%;
    background: #EF3340;
    flex-shrink: 0;
