<style>
:root{--gc:#EF3340;--gg:#00A341;--gbg:#FFF5F5;--gbr:#F0E0E0;--gsoft:#FFF0F0}

.gp-s,.gp-s *{font-family:var(--font-body-family,inherit)}
.gp-h2,.gp-vp-li-t,.gp-fq-q,.gp-ig-nm,.gp-rv-nm{font-family:var(--font-heading-family,inherit)}

.gp-s{padding:64px 24px;width:100vw;position:relative;left:50%;right:50%;margin-left:-50vw;margin-right:-50vw;box-sizing:border-box;}
.gp-s-cream{background:var(--gbg)}
.gp-s-white{background:#fff;border-top:1px solid var(--gbr)}
.gp-fc{width:100vw;position:relative;left:50%;right:50%;margin-left:-50vw;margin-right:-50vw;box-sizing:border-box;}
.gp-inner{max-width:1100px;margin:0 auto}
.gp-inner-sm{max-width:960px;margin:0 auto}
.gp-inner-xs{max-width:740px;margin:0 auto}
.gp-ey{font-size:12px;text-transform:uppercase;letter-spacing:2.5px;color:var(--gc);font-weight:700;margin-bottom:12px;text-align:center}
.gp-h2{font-size:clamp(28px,4vw,44px);font-weight:800;text-align:center;line-height:1.1;margin:0 0 10px;letter-spacing:-0.02em;color:#000}
.gp-sub{font-size:17px;text-align:center;color:#666;margin-bottom:40px;line-height:1.65}

/* MARQUEE */
.gp-mq{padding:20px 0;overflow:hidden;border-top:1px solid var(--gbr);border-bottom:1px solid var(--gbr);background:var(--gbg)}
.gp-mq-t{display:flex;width:max-content;animation:gpScr 28s linear infinite}
.gp-mq-t:hover{animation-play-state:paused}
@keyframes gpScr{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}
.gp-mq-i{display:inline-flex;align-items:center;gap:10px;padding:0 32px;white-space:nowrap;font-size:16px;font-weight:700;color:#000;letter-spacing:-0.01em}
.gp-mq-ic{width:36px;height:36px;background:#fff;border-radius:50%;display:flex;align-items:center;justify-content:center;flex-shrink:0;box-shadow:0 2px 8px rgba(0,0,0,.05)}
.gp-mq-ic svg{width:18px;height:18px}
.gp-mq-sp{color:var(--gc);font-size:8px;padding:0 4px}

/* COMPARISON */
.gp-cmp-wrap{background:#fff;border-radius:16px;padding:36px 28px;border:1px solid var(--gbr);overflow-x:auto;-webkit-overflow-scrolling:touch}
.gp-ct{width:100%;border-collapse:separate;border-spacing:0;font-size:15px}
.gp-ct thead th{padding:14px;text-align:center;font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:.6px;border-bottom:2px solid var(--gbr);color:#999}
.gp-ct thead th:first-child{text-align:left}
.gp-ct thead th.hl{color:var(--gc);background:rgba(239,51,64,.03)}
.gp-ct tbody td{padding:12px 14px;text-align:center;border-bottom:1px solid var(--gbr);color:#666;font-size:14px}
.gp-ct tbody td:first-child{text-align:left;color:#000;font-weight:600}
.gp-ct tbody td.hlc{color:#000;font-weight:700;background:rgba(239,51,64,.04)}
.gp-ct tbody tr:last-child td{border-bottom:none}
.gp-ck{color:var(--gg);font-weight:700;font-size:16px}
.gp-cx{color:#ccc;font-size:16px}
.gp-cf{text-align:center;margin-top:24px;font-size:15px;color:#666;font-style:italic}
.gp-cf strong{color:var(--gc);font-style:normal}

/* VALUE PROPS */
.gp-vp-split{display:grid;grid-template-columns:1fr 1fr;gap:48px;align-items:center}
.gp-vp-img{border-radius:20px;overflow:hidden}
.gp-vp-img img{width:100%;display:block;border-radius:20px}
.gp-vp-content .gp-ey{text-align:left}
.gp-vp-content .gp-h2{text-align:left;font-size:clamp(22px,3vw,34px)}
.gp-vp-content .gp-sub{text-align:left;margin-bottom:24px;font-size:15px}
.gp-vp-list{display:flex;flex-direction:column;gap:16px}
.gp-vp-li{display:flex;align-items:flex-start;gap:12px}
.gp-vp-li-ic{width:36px;height:36px;min-width:36px;background:var(--gsoft);border-radius:10px;display:flex;align-items:center;justify-content:center}
.gp-vp-li-ic svg{width:18px;height:18px}
.gp-vp-li-t{font-size:16px;font-weight:700;color:#000;margin-bottom:2px}
.gp-vp-li-d{font-size:14px;color:#666;line-height:1.6}

/* STATS */
.gp-st-r{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin-top:48px;padding-top:40px;border-top:1px solid var(--gbr)}
.gp-st{text-align:center}
.gp-st-n{font-size:clamp(26px,3.5vw,40px);font-weight:800;color:var(--gc);line-height:1;letter-spacing:-0.02em;font-family:var(--font-heading-family,inherit)}
.gp-st-l{font-size:11px;color:#999;text-transform:uppercase;letter-spacing:1px;font-weight:600;margin-top:4px}

/* INGREDIENTS */
.gp-ig{display:flex;flex-direction:column;gap:10px}
.gp-ig-c{display:flex;align-items:center;gap:16px;padding:18px 22px;background:#fff;border-radius:12px;border:1px solid var(--gbr);transition:border-color .2s}
.gp-ig-c:hover{border-color:var(--gc)}
.gp-ig-n{width:30px;height:30px;min-width:30px;background:var(--gc);color:#fff;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:800}
.gp-ig-info{flex:1}
.gp-ig-nm{font-size:16px;font-weight:700;color:#000;margin-bottom:2px}
.gp-ig-why{font-size:14px;color:#666}
.gp-ig-tag{font-size:10px;text-transform:uppercase;letter-spacing:1px;color:var(--gc);font-weight:700;background:rgba(239,51,64,.08);padding:4px 10px;border-radius:100px;white-space:nowrap}
.gp-ig-bot{text-align:center;margin-top:32px}
.gp-ig-badge{display:inline-flex;align-items:center;gap:8px;padding:12px 24px;background:var(--gc);border-radius:100px;font-size:13px;font-weight:700;color:#fff}
.gp-ig-note{font-size:13px;color:#999;margin-top:12px;font-style:italic}

/* REVIEWS */
.gp-rv-g{display:grid;grid-template-columns:repeat(2,1fr);gap:16px;max-width:900px;margin:0 auto}
.gp-rv-c{background:#fff;border-radius:14px;padding:26px 22px;border:1px solid var(--gbr);display:flex;flex-direction:column}
.gp-rv-stars{display:flex;gap:2px;margin-bottom:12px}
.gp-rv-stars svg{width:14px;height:14px}
.gp-rv-txt{font-size:15px;color:#444;line-height:1.65;margin-bottom:16px;font-style:italic;flex:1}
.gp-rv-auth{display:flex;align-items:center;gap:10px;padding-top:14px;border-top:1px solid var(--gbr)}
.gp-rv-av{width:34px;height:34px;background:var(--gc);border-radius:50%;display:flex;align-items:center;justify-content:center;color:#fff;font-size:13px;font-weight:700;flex-shrink:0}
.gp-rv-nm{font-size:14px;font-weight:700;color:#000}
.gp-rv-badge{font-size:12px;color:#999}
.gp-rv-stbig{display:flex;justify-content:center;gap:4px;margin-bottom:8px}
.gp-rv-stbig svg{width:20px;height:20px}

/* FAQ */
.gp-fq{display:flex;flex-direction:column}
.gp-fq-i{border-bottom:1px solid var(--gbr)}
.gp-fq-i:first-child{border-top:1px solid var(--gbr)}
.gp-fq-tog{display:none}
.gp-fq-q{display:flex;align-items:center;justify-content:space-between;padding:20px 0;cursor:pointer;font-size:16px;font-weight:600;color:#000;line-height:1.4;transition:color .2s;user-select:none;-webkit-user-select:none}
.gp-fq-q:hover{color:var(--gc)}
.gp-fq-chv{width:20px;height:20px;min-width:20px;transition:transform .3s;margin-left:16px}
.gp-fq-a{max-height:0;overflow:hidden;transition:max-height .35s ease}
.gp-fq-a-in{padding:0 0 20px;font-size:15px;color:#555;line-height:1.75}
.gp-fq-tog:checked~.gp-fq-q .gp-fq-chv{transform:rotate(180deg)}
.gp-fq-tog:checked~.gp-fq-q{color:var(--gc)}
.gp-fq-tog:checked~.gp-fq-a{max-height:300px}

/* FINAL CTA */
.gp-fc{background:var(--gc);padding:80px 40px;text-align:center}
.gp-fc-perks{display:flex;justify-content:center;flex-wrap:wrap;gap:12px;margin-bottom:40px}
.gp-fc-pk{display:inline-flex;align-items:center;gap:8px;font-size:14px;color:#fff;font-weight:600;background:rgba(255,255,255,.15);padding:10px 18px;border-radius:100px}
.gp-fc-pk svg{width:16px;height:16px;flex-shrink:0}
.gp-fc-btn{display:inline-flex;align-items:center;gap:10px;padding:18px 48px;background:#fff;color:var(--gc);font-size:18px;font-weight:800;border:none;border-radius:12px;cursor:pointer;text-decoration:none;transition:transform .15s,box-shadow .2s;text-transform:uppercase;letter-spacing:.5px}
.gp-fc-btn:hover{transform:translateY(-2px);box-shadow:0 12px 32px rgba(0,0,0,.2)}
.gp-fc-pn{margin-top:20px;font-size:15px;color:rgba(255,255,255,.8)}
.gp-fc-pn strong{color:#fff}
.gp-fc-gt{margin-top:24px;display:flex;align-items:center;justify-content:center;gap:8px;font-size:14px;color:rgba(255,255,255,.7)}

@media(max-width:749px){
.gp-s{padding:48px 16px}
.gp-vp-split{grid-template-columns:1fr;gap:28px}
.gp-st-r{grid-template-columns:repeat(2,1fr);gap:12px}
.gp-ct{min-width:500px}
.gp-rv-g{grid-template-columns:1fr}
.gp-cmp-wrap{padding:16px 10px}
.gp-fc{padding:60px 20px}
.gp-fc-btn{width:100%;justify-content:center;font-size:16px;padding:16px 24px}
.gp-ig-tag{display:none}
}
</style>

<svg style="display:none" xmlns="http://www.w3.org/2000/svg">
<symbol id="gp-star" viewBox="0 0 24 24"><polygon fill="#EF3340" points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/></symbol>
