<div class="gp-s gp-s-white">
  <div class="gp-inner">
    <div class="gp-vp-split">
      <div class="gp-vp-img">
        <img src="https://www.gameplanskincare.com/cdn/shop/files/gp_products_-2.jpg?v=1721318072&width=900" alt="GamePlan Post-Sweat Sport Wipes" loading="lazy">
